# TCL Scripting Best Practices

## 1. Always check for active design
```tcl
set design [GetActiveDesign]
if {$design eq ""} {
    puts "ERROR: No active design"
    return
}
```

## 2. Use catch for error handling
```tcl
if {[catch {set result [SomeCommand]} err]} {
    puts "Error: $err"
}
```

## 3. Close file handles
```tcl
set fp [open $filename w]
# ... write data ...
close $fp
```

## 4. Use proc for reusable functions
```tcl
proc findComponent {design refdes} {
    foreach page [GetPages $design] {
        foreach part [GetPartInsts $page] {
            if {[GetPropValue $part "Reference"] eq $refdes} {
                return $part
            }
        }
    }
    return ""
}
```

## 5. Iterate safely
```tcl
# Always check list is not empty before iterating
set parts [GetPartInsts $page]
if {[llength $parts] > 0} {
    foreach part $parts { ... }
}
```

# BOM (Bill of Materials) Export Script
# Exports component data to CSV format

proc export_bom {{filename ""}} {
    set design [GetActiveDesign]
    if {$design eq ""} {
        puts "ERROR: No active design"
        return
    }

    if {$filename eq ""} {
        set filename "[GetDesignName $design]_BOM.csv"
    }

    set fp [open $filename w]
    puts $fp "RefDes,Part Name,Value,Footprint,Part Number,Manufacturer"

    set count 0
    foreach page [GetPages $design] {
        foreach part [GetPartInsts $page] {
            set refdes [GetPropValue $part "Reference"]
            set pname [GetPropValue $part "Part Name"]
            set value [GetPropValue $part "Value"]
            set fp_val [GetPropValue $part "PCB Footprint"]
            set pn [GetPropValue $part "Part Number"]
            set mfr [GetPropValue $part "Manufacturer"]

            puts $fp "$refdes,$pname,$value,$fp_val,$pn,$mfr"
            incr count
        }
    }

    close $fp
    puts "Exported $count components to $filename"
}

export_bom

# Batch Property Update Script
# Updates a property value for components matching a pattern

proc batch_update_property {refdes_pattern prop_name new_value} {
    set design [GetActiveDesign]
    if {$design eq ""} {
        puts "ERROR: No active design"
        return
    }

    set updated 0
    foreach page [GetPages $design] {
        foreach part [GetPartInsts $page] {
            set refdes [GetPropValue $part "Reference"]
            if {[string match $refdes_pattern $refdes]} {
                set old_value [GetPropValue $part $prop_name]
                SetPropValue $part $prop_name $new_value
                puts "Updated $refdes: $prop_name '$old_value' -> '$new_value'"
                incr updated
            }
        }
    }

    puts "Updated $updated components"
    SaveDesign $design
}

# Usage examples:
# batch_update_property "R*" "PCB Footprint" "0402"
# batch_update_property "C*" "Manufacturer" "Murata"
